async (params, browser) => {
  // Open OpenSea rankings
  await browser.open('https://opensea.io/rankings')

  // Wait for rankings to load
  await browser.waitForSelector('table, [class*=\'ranking\'], a[href*=\'/collection/\']', 15000)

  // Let rankings render
  await browser.wait(3000)

  // Scroll to load more rankings
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Scroll further for more collections
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Extract ranking data
  const result = await browser.evaluate(`const collections = []; const rows = document.querySelectorAll('table tbody tr, [class*="ranking-row"], [class*="RankingRow"]'); if (rows.length > 0) { rows.forEach((el, i) => { if (i >= 25) return; const cells = el.querySelectorAll('td'); const nameEl = el.querySelector('a[href*="/collection/"], [class*="name"]'); const link = el.querySelector('a[href*="/collection/"]'); let volume = ''; let floor = ''; let change = ''; if (cells.length >= 3) { volume = cells[2]?.textContent?.trim() || ''; floor = cells[3]?.textContent?.trim() || ''; change = cells[4]?.textContent?.trim() || ''; } else { const spans = el.querySelectorAll('span, div'); const texts = Array.from(spans).map(s => s.textContent.trim()).filter(Boolean); if (texts.length >= 3) { volume = texts[1] || ''; floor = texts[2] || ''; change = texts[3] || ''; } } collections.push({ rank: i + 1, name: nameEl?.textContent?.trim() || '', volume: volume, floor_price: floor, change: change, url: link?.href || '' }); }); } else { const links = document.querySelectorAll('a[href*="/collection/"]'); const seen = new Set(); links.forEach((el, i) => { if (collections.length >= 25) return; const href = el.href; if (seen.has(href)) return; seen.add(href); const name = el.textContent?.trim() || ''; if (!name || name.length > 100) return; const parent = el.closest('div, li, tr'); const priceEl = parent?.querySelector('[class*="price"], [class*="floor"], [class*="volume"]'); collections.push({ rank: collections.length + 1, name: name, volume: '', floor_price: priceEl?.textContent?.trim() || '', change: '', url: href }); }); } return { collection_count: collections.length, collections: collections }`)

  return result
}
